			ValueStore valueStore = lmdb.getValueStore();
			long predicateId = valueStore.getId(predicate);
			String index = lmdb.selectBestIndex(LmdbValue.UNKNOWN_ID, predicateId, LmdbValue.UNKNOWN_ID,
					LmdbValue.UNKNOWN_ID);

			Set<Long> expectedSubjects = ids(valueStore, subjects);
